Hi,
I am trying to create a sample excel file but i am getting error **'e.createWriteStream is not a function'**.
below is code to create the file-

```
import { Component } from '@angular/core';
import { NavController, Platform } from 'ionic-angular';
import * as Excel from "exceljs/dist/exceljs.min.js";
import * as ExcelProper from "exceljs";

@Component({
  selector: 'page-home',
  templateUrl: 'home.html'
})
export class HomePage {

  constructor(platform: Platform) {
    platform.ready().then(() => {
      this.createSheet();
    });
  }

  ionViewDidLoad() {
  }

  createSheet() {
    let workbook: ExcelProper.Workbook = new Excel.Workbook();
    var worksheet = workbook.addWorksheet('My Sheet');

    worksheet.columns = [
      { header: 'Id', key: 'id', width: 10 },
      { header: 'Name', key: 'name', width: 32 },
      { header: 'D.O.B.', key: 'DOB', width: 10 }
    ];
    worksheet.addRow({ id: 1, name: 'Ionic Android', dob: new Date(1970, 1, 1) });
    worksheet.addRow({ id: 2, name: 'Ionic iOS', dob: new Date(1965, 1, 7) });
    var tempFilePath = 'PATH/temp.xlsx'; // PATH is where you want to create your file

    workbook.xlsx.writeFile(tempFilePath).then(function () {
      console.log('file is written');
    });
  }
}
```


This is my ionic info output:
```
